import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { orderService } from '../../services/orderService';
import Loader from '../../components/shared/Loader';
import useTranslation from '../../hooks/useTranslation';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip as RechartsTooltip, ResponsiveContainer, PieChart, Pie, Cell, BarChart, Bar } from 'recharts';
import { TrendingUp, TrendingDown, AlertTriangle, Package, Users, DollarSign, ShoppingBag } from 'lucide-react';

const AdminDashboard = () => {
  const { t } = useTranslation('admin');
  const [stats, setStats] = useState({
    totalRevenue: '0.00',
    totalOrders: 0,
    totalProducts: 0,
    totalUsers: 0,
  });
  const [trends, setTrends] = useState({ revenue: 0, orders: 0, users: 0 });
  const [chartData, setChartData] = useState([]);
  const [pieData, setPieData] = useState([]);
  const [topProducts, setTopProducts] = useState([]);
  const [recentOrders, setRecentOrders] = useState([]);
  const [lowStockAlerts, setLowStockAlerts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [timeframe, setTimeframe] = useState('all'); // 'today', 'week', 'month', 'year', 'all'

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const res = await orderService.getAdminStats(timeframe);
        const data = res.data;
        
        setStats({
          totalRevenue: data.totalRevenue,
          totalOrders: data.totalOrders,
          totalProducts: data.totalProducts,
          totalUsers: data.totalUsers,
        });
        
        setTrends(data.trends || { revenue: 0, orders: 0, users: 0 });
        setChartData(data.revenueByDay || []);
        setPieData(data.ordersByStatus || []);
        setLowStockAlerts(data.lowStockAlerts || []);
        setTopProducts(data.topProducts || []);

        // Fetch recent orders
        const ordersRes = await orderService.getAllOrders('', 'All', 1, 5);
        setRecentOrders(ordersRes.orders || []);
      } catch (err) {
        console.error("Failed to load dashboard data", err);
      } finally {
        setLoading(false);
      }
    };
    fetchDashboardData();
  }, [timeframe]);

  const handleExportCSV = async () => {
    try {
      const url = orderService.exportOrdersCSV();
      // Needs authorization header attached if strictly protected,
      // Workaround: We can fetch it as blob then trigger download
      const response = await fetch(url, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem('token')}`
        }
      });
      if (!response.ok) throw new Error('Export failed');
      const blob = await response.blob();
      const downloadUrl = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = downloadUrl;
      a.download = 'orders.csv';
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(downloadUrl);
      a.remove();
    } catch (err) {
      alert("Failed to export CSV");
      console.error(err);
    }
  };

  const COLORS = ['#8B6914', '#1a1a2e', '#4f46e5', '#10b981', '#f43f5e'];

  if (loading) return <Loader />;

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-serif text-black">{t?.dashboard?.title || 'Dashboard'}</h1>
        
        <div className="flex gap-4">
          <select 
            value={timeframe} 
            onChange={(e) => setTimeframe(e.target.value)}
            className="border border-gray-300 p-2 text-sm focus:outline-none focus:border-black rounded bg-white shadow-sm"
          >
            <option value="today">Today</option>
            <option value="week">This Week</option>
            <option value="month">This Month</option>
            <option value="year">This Year</option>
            <option value="all">All Time</option>
          </select>
          <button 
            onClick={handleExportCSV}
            className="bg-black text-white px-4 py-2 text-sm font-medium rounded hover:bg-gold transition-colors shadow-sm"
          >
            {t?.common?.export || 'Export Orders (CSV)'}
          </button>
        </div>
      </div>
      
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {[
          { key: 'totalRevenue', label: 'Total Revenue', value: `$${stats.totalRevenue}`, icon: DollarSign, trend: trends.revenue },
          { key: 'totalOrders', label: 'Total Orders', value: stats.totalOrders, icon: ShoppingBag, trend: trends.orders },
          { key: 'totalProducts', label: 'Total Products', value: stats.totalProducts, icon: Package, trend: null },
          { key: 'totalUsers', label: 'Total Users', value: stats.totalUsers, icon: Users, trend: trends.users },
        ].map((stat, idx) => {
          const Icon = stat.icon;
          return (
          <div key={idx} className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
            <div className="flex justify-between items-start mb-4">
              <div className="w-12 h-12 rounded-lg bg-gray-50 flex items-center justify-center text-brand">
                <Icon size={24} />
              </div>
              {stat.trend !== null && (
                <div className={`flex items-center gap-1 text-xs font-bold px-2 py-1 rounded-full ${stat.trend >= 0 ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                  {stat.trend >= 0 ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                  <span>{Math.abs(stat.trend)}%</span>
                </div>
              )}
            </div>
            <div>
              <p className="text-sm font-medium text-gray-500 mb-1">{stat.label}</p>
              <h3 className="text-3xl font-bold text-gray-900 tracking-tight">{stat.value}</h3>
            </div>
          </div>
        )})}
      </div>

      {/* Charts Section */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
        {/* Line Chart */}
        <div className="bg-white shadow-sm border border-gray-100 rounded-xl p-6 lg:col-span-2">
          <h3 className="text-lg font-serif text-brand mb-6">Revenue Overview (Last 30 Days)</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 5, right: 20, bottom: 5, left: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="date" tick={{fontSize: 12, fill: '#64748b'}} tickLine={false} axisLine={false} />
                <YAxis tick={{fontSize: 12, fill: '#64748b'}} tickLine={false} axisLine={false} tickFormatter={(val) => `$${val}`} />
                <RechartsTooltip contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} />
                <Line type="monotone" dataKey="revenue" stroke="#8B6914" strokeWidth={3} dot={{r: 4, fill: '#8B6914', strokeWidth: 0}} activeDot={{r: 6}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Pie Chart */}
        <div className="bg-white shadow-sm border border-gray-100 rounded-xl p-6">
          <h3 className="text-lg font-serif text-brand mb-6">Orders by Status</h3>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <RechartsTooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="flex flex-wrap justify-center gap-3 mt-4">
            {pieData.map((entry, index) => (
              <div key={index} className="flex items-center gap-2 text-xs text-gray-600 font-medium">
                <span className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[index % COLORS.length] }}></span>
                {entry.name} ({entry.value})
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Low Stock Alerts */}
      {lowStockAlerts.length > 0 && (
        <div className="bg-red-50 border border-red-100 rounded-xl p-6 mb-8 shadow-sm">
          <div className="flex items-center gap-3 mb-4 text-red-700">
            <AlertTriangle size={24} />
            <h3 className="text-lg font-bold">Low Stock Alerts</h3>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
            {lowStockAlerts.map(prod => (
              <div key={prod.id} className="bg-white p-3 rounded-lg flex items-center gap-3 shadow-sm border border-red-100">
                <img src={prod.image} alt={prod.name} className="w-12 h-12 object-cover rounded" />
                <div>
                  <p className="text-xs font-medium text-gray-900 line-clamp-1">{prod.name}</p>
                  <p className="text-xs font-bold text-red-600 mt-1">{prod.stock} left</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Top Products Table */}
        <div className="bg-white shadow-sm border border-gray-200 rounded-xl overflow-hidden md:col-span-1 flex flex-col">
          <div className="px-6 py-5 border-b border-gray-200 flex justify-between items-center bg-gray-50">
            <h2 className="text-lg font-serif text-black">{t?.dashboard?.topProducts || 'Top Products'}</h2>
          </div>
          <div className="p-6 grow flex flex-col justify-center">
            {topProducts.length > 0 ? (
              <ResponsiveContainer width="100%" height={250}>
                <BarChart data={topProducts} layout="vertical" margin={{ top: 0, right: 0, bottom: 0, left: -20 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" tick={{fontSize: 10, fill: '#64748b'}} width={100} axisLine={false} tickLine={false} />
                  <RechartsTooltip cursor={{fill: 'transparent'}} />
                  <Bar dataKey="quantitySold" fill="#8B6914" radius={[0, 4, 4, 0]} barSize={20} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <p className="text-center text-gray-500 text-sm">No data available</p>
            )}
          </div>
        </div>

        {/* Recent Orders Table */}
        <div className="bg-white shadow-sm border border-gray-200 rounded-xl overflow-hidden md:col-span-2">
          <div className="px-6 py-5 border-b border-gray-200 flex justify-between items-center bg-gray-50">
            <h2 className="text-lg font-serif text-black">{t?.dashboard?.recentOrders || 'Recent Orders'}</h2>
          <Link to="/admin/orders" className="text-sm font-medium text-[#8B6914] hover:text-black transition-colors">
            {t?.common?.all || 'View All Orders'}
          </Link>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-gray-50 text-gray-500 text-xs uppercase tracking-wider border-b border-gray-200">
                <th className="px-6 py-4 font-medium">Order ID</th>
                <th className="px-6 py-4 font-medium">Customer</th>
                <th className="px-6 py-4 font-medium hidden sm:table-cell">Date</th>
                <th className="px-6 py-4 font-medium hidden sm:table-cell">Total</th>
                <th className="px-6 py-4 font-medium text-right">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {recentOrders.length > 0 ? recentOrders.map((order, index) => (
                <tr key={order._id} className="hover:bg-gray-50 transition-colors cursor-pointer" onClick={() => window.location.href = `/admin/orders/${order._id}`}>
                  <td className="px-6 py-4 text-sm font-bold text-brand">#{order._id.substring(order._id.length - 6).toUpperCase()}</td>
                  <td className="px-6 py-4 text-sm text-gray-700 font-medium">{order.shippingAddress?.fullName || 'N/A'}</td>
                  <td className="px-6 py-4 text-sm text-gray-500 hidden sm:table-cell">{new Date(order.createdAt).toLocaleDateString()}</td>
                  <td className="px-6 py-4 text-sm font-bold text-gray-700 hidden sm:table-cell">${order.totalAmount || order.total}</td>
                  <td className="px-6 py-4 text-sm text-right">
                    <span className={`px-3 py-1 rounded-full text-xs font-bold ${
                      order.status === 'Delivered' ? 'bg-green-100 text-green-800' :
                      order.status === 'Shipped' ? 'bg-blue-100 text-blue-800' :
                      order.status === 'Cancelled' ? 'bg-red-100 text-red-800' :
                      'bg-yellow-100 text-yellow-800'
                    }`}>
                      {order.status}
                    </span>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan="5" className="text-center py-6 text-gray-500">No recent orders</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
      </div>
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { orderService } from '../../../services/orderService';
import Loader from '../../../components/shared/Loader';
import useTranslation from '../../../hooks/useTranslation';
import toast from 'react-hot-toast';
import ConfirmationModal from '../../../components/shared/ConfirmationModal';

const OrderList = () => {
  const { t } = useTranslation('admin');
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  
  // Server-side State Logic
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('All');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalRecords, setTotalRecords] = useState(0);

  // Bulk Selection
  const [selectedIds, setSelectedIds] = useState([]);
  const [bulkStatus, setBulkStatus] = useState('');

  // Modal State
  const [selectedOrder, setSelectedOrder] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalLoading, setModalLoading] = useState(false);

  // Confirmation Modal
  const [confirmModal, setConfirmModal] = useState({ isOpen: false, data: null, message: '', title: '' });

  const limit = 15;

  const fetchOrders = async () => {
    try {
      setLoading(true);
      const res = await orderService.getAllOrders(searchTerm, statusFilter, page, limit);
      setOrders(res.data);
      setTotalPages(res.pages);
      setTotalRecords(res.total);
      setSelectedIds([]); // Reset selection on fetch
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

   
  useEffect(() => {
    fetchOrders();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page, statusFilter]); // search fires manually via button click or Enter key to prevent heavy DB hits

  const handleSearch = (e) => {
    e.preventDefault();
    setPage(1); // Reset to first page
    fetchOrders();
  };

  const handleStatusChangeFilter = (e) => {
    setStatusFilter(e.target.value);
    setPage(1); // Reset to first page whenever status changes
  };

  const handleStatusChangeClick = (id, newStatus) => {
    setConfirmModal({
       isOpen: true,
       data: { id, newStatus, trackingNumber: null },
       title: 'Update Order Status',
       message: `Change order status to ${newStatus}?`
    });
  };

  const executeStatusChange = async () => {
    const { id, newStatus } = confirmModal.data;
    let trackingNumber = null;
    
    setConfirmModal({ ...confirmModal, isOpen: false });

    if (newStatus === 'shipped') {
       trackingNumber = window.prompt(t?.orders?.trackingPrompt || "Enter tracking number for this shipment (optional):");
    }

    try {
      await orderService.updateOrderStatus(id, newStatus, trackingNumber);
      toast.success(`Order marked as ${newStatus}`);
      fetchOrders();
      if (selectedOrder && selectedOrder._id === id) {
        fetchOrderDetails(id);
      }
    } catch (err) {
      console.error(err);
      toast.error('Failed to update status');
    }
  };

  const handleSelectAll = (e) => {
    if (e.target.checked) setSelectedIds(orders.map(o => o._id));
    else setSelectedIds([]);
  };

  const handleSelectOne = (id, e) => {
    e.stopPropagation();
    if (selectedIds.includes(id)) setSelectedIds(selectedIds.filter(i => i !== id));
    else setSelectedIds([...selectedIds, id]);
  };

  const handleBulkStatusUpdateClick = async () => {
    if (!bulkStatus) return toast.error('Select a status');
    if (selectedIds.length === 0) return toast.error('Select at least one order');

    setConfirmModal({
       isOpen: true,
       data: 'bulk',
       title: 'Confirm Bulk Update',
       message: `Update ${selectedIds.length} orders to ${bulkStatus}?`
    });
  };

  const executeBulkStatusChange = async () => {
    setConfirmModal({ ...confirmModal, isOpen: false });
    try {
      setLoading(true);
      for (const id of selectedIds) {
        await orderService.updateOrderStatus(id, bulkStatus, null);
      }
      toast.success(`${selectedIds.length} orders updated to ${bulkStatus}`);
      setBulkStatus('');
      fetchOrders();
    } catch (err) {
      console.error("Bulk action failed", err);
      toast.error('Bulk update failed partially or completely.');
      fetchOrders();
    } finally {
      setLoading(false);
    }
  };

  const confirmAction = () => {
    if (confirmModal.data === 'bulk') {
       executeBulkStatusChange();
    } else {
       executeStatusChange();
    }
  };

  const fetchOrderDetails = async (id) => {
    try {
      setModalLoading(true);
      setIsModalOpen(true);
      const res = await orderService.getOrderById(id);
      setSelectedOrder(res.data);
    } catch (err) {
      console.error("Failed to load order details", err);
      alert('Failed to load order details');
      setIsModalOpen(false);
    } finally {
      setModalLoading(false);
    }
  };

  const openModal = (id, e) => {
    if (e) {
      // Prevent opening modal if clicking on select/checkbox/buttons
      if (['INPUT', 'SELECT', 'BUTTON', 'A'].includes(e.target.tagName)) return;
    }
    fetchOrderDetails(id);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedOrder(null);
  };


  const statusColors = {
    'pending': 'bg-yellow-100 text-yellow-800',
    'processing': 'bg-blue-100 text-blue-800',
    'shipped': 'bg-indigo-100 text-indigo-800',
    'delivered': 'bg-green-100 text-green-800',
    'cancelled': 'bg-red-100 text-red-800',
  };

  return (
    <div>
      <h1 className="text-2xl font-serif text-black mb-8">{t?.orders?.title || 'Order Management'}</h1>

      <div className="bg-white shadow-sm border border-gray-100 rounded overflow-hidden">
        
        {/* Toolbar / Search Header */}
        <div className="p-4 border-b border-gray-100 bg-white flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4 w-full md:w-auto">
            <span className="text-sm font-medium text-gray-700 whitespace-nowrap">{selectedIds.length} Selected</span>
            <select 
              value={bulkStatus} 
              onChange={(e) => setBulkStatus(e.target.value)} 
              className="border border-gray-300 p-2 text-sm focus:outline-none focus:border-black bg-white disabled:opacity-50"
              disabled={selectedIds.length === 0}
            >
              <option value="">-- Bulk Status Update --</option>
              <option value="pending">Pending</option>
              <option value="processing">Processing</option>
              <option value="shipped">Shipped</option>
              <option value="delivered">Delivered</option>
              <option value="cancelled">Cancelled</option>
            </select>
            {bulkStatus && (
              <button onClick={handleBulkStatusUpdateClick} className="bg-black text-white px-4 py-1.5 text-xs uppercase font-bold tracking-wider hover:bg-gold transition-colors">Apply</button>
            )}
          </div>

          <form onSubmit={handleSearch} className="flex w-full md:w-96">
            <input 
              type="text" 
              placeholder={t?.common?.search || "Search by ID, Name, Email..."} 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full border border-gray-300 p-2 text-sm focus:outline-none focus:border-black transition-colors rounded-l border-r-0"
            />
            <button type="submit" className="bg-black text-white px-4 text-sm font-medium hover:bg-gray-800 transition-colors rounded-r">
              {t?.common?.search || 'Search'}
            </button>
          </form>
        </div>

        {/* Quick Filter Tabs */}
        <div className="flex border-b border-gray-100 bg-gray-50 overflow-x-auto">
          {['All', 'pending', 'processing', 'shipped', 'delivered', 'cancelled'].map(tab => (
            <button
              key={tab}
              onClick={() => { setStatusFilter(tab); setPage(1); }}
              className={`px-6 py-3 text-sm font-bold uppercase tracking-wide whitespace-nowrap transition-colors border-b-2 ${statusFilter === tab ? 'border-brand text-brand bg-white' : 'border-transparent text-gray-500 hover:text-black hover:bg-gray-100'}`}
            >
              {tab}
            </button>
          ))}
        </div>

        {/* Data Table */}
        <div className="overflow-x-auto min-h-[400px]">
          {loading ? (
            <Loader />
          ) : (
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-[#1a1a2e] text-white text-xs uppercase tracking-wider">
                  <th className="px-4 py-4 w-10 text-center rounded-tl-sm">
                    <input type="checkbox" onChange={handleSelectAll} checked={orders.length > 0 && selectedIds.length === orders.length} className="w-4 h-4 accent-[#8B6914]" />
                  </th>
                  <th className="px-6 py-4 font-medium">{t?.orders?.orderId || 'Order UUID'} / {t?.orders?.customer || 'Customer'}</th>
                  <th className="px-6 py-4 font-medium">{t?.common?.date || 'Date Issued'}</th>
                  <th className="px-6 py-4 font-medium">{t?.orders?.items || 'Items'} / {t?.orders?.total || 'Total'}</th>
                  <th className="px-6 py-4 font-medium">{t?.common?.status || 'Status Check'}</th>
                  <th className="px-6 py-4 font-medium text-right rounded-tr-sm">{t?.common?.actions || 'Actions'}</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {orders.length > 0 ? orders.map((order, index) => (
                  <tr key={order._id} className={`${index % 2 === 0 ? 'bg-white' : 'bg-gray-50'} hover:bg-gray-100 transition-colors cursor-pointer group`} onClick={(e) => openModal(order._id, e)}>
                    <td className="px-4 py-4 text-center" onClick={(e) => e.stopPropagation()}>
                      <input type="checkbox" checked={selectedIds.includes(order._id)} onChange={(e) => handleSelectOne(order._id, e)} className="w-4 h-4 accent-[#8B6914]" />
                    </td>
                    
                    <td className="px-6 py-4">
                      <div className="text-sm font-medium text-black truncate max-w-[150px] font-mono">{order._id}</div>
                      <div className="text-sm text-gray-800 font-medium mt-1">{order.user?.name}</div>
                      <div className="text-xs text-gray-500">{order.user?.email}</div>
                    </td>
                    
                    <td className="px-6 py-4 text-sm text-gray-500">{new Date(order.createdAt).toLocaleString()}</td>
                    
                    <td className="px-6 py-4">
                      <div className="text-sm text-gray-600 font-medium">{order.items?.length || 0} Items</div>
                      <div className="text-sm font-bold text-black mt-1">${order.total?.toFixed(2)}</div>
                    </td>
                    
                    <td className="px-6 py-4 text-sm">
                      <div className="flex flex-col gap-1 items-start">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold tracking-wide uppercase ${statusColors[order.status] || 'bg-gray-100 text-gray-800'}`}>
                          {t?.common?.[order.status] || order.status}
                        </span>
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold tracking-wide uppercase ${order.payment?.status === 'paid' ? 'bg-green-100 text-green-800' : 'bg-red-50 text-red-800 border border-red-100'}`}>
                          PAY: {order.payment?.status || 'UNKNOWN'}
                        </span>
                        <span className="text-[10px] text-gray-500 font-mono uppercase bg-gray-50 px-1 rounded border border-gray-200">
                          {order.payment?.method || 'N/A'}
                        </span>
                      </div>
                    </td>
                    
                     <td className="px-6 py-4 text-sm text-right align-top" onClick={(e) => e.stopPropagation()}>
                      <div className="flex flex-col items-end gap-2">
                         <select 
                           value={order.status}
                           onChange={(e) => handleStatusChangeClick(order._id, e.target.value)}
                           className="border border-gray-300 p-1.5 text-xs focus:outline-none focus:border-black bg-white w-32 cursor-pointer rounded-sm font-medium"
                         >
                           <option value="pending">{t?.common?.pending || 'Pending'}</option>
                           <option value="processing">{t?.common?.processing || 'Processing'}</option>
                           <option value="shipped">{t?.common?.shipped || 'Shipped'}</option>
                           <option value="delivered">{t?.common?.delivered || 'Delivered'}</option>
                           <option value="cancelled">{t?.common?.cancelled || 'Cancelled'}</option>
                         </select>
                         
                         <div className="flex flex-col items-center gap-2 mt-2 w-full justify-end">
                           <button onClick={(e) => openModal(order._id, e)} className="bg-brand text-white w-full px-3 py-1.5 rounded-sm hover:bg-gold text-xs font-bold uppercase tracking-wider shadow-sm transition-colors text-center">
                             Quick View
                           </button>
                           <button onClick={(e) => { e.stopPropagation(); window.open(`/admin/orders/${order._id}?print=true`, '_blank'); }} className="bg-gray-800 text-white w-full px-3 py-1.5 rounded-sm hover:bg-black text-xs font-bold uppercase tracking-wider shadow-sm transition-colors text-center">
                             Print Invoice
                           </button>
                         </div>
                      </div>
                    </td>
                    
                  </tr>
                )) : (
                  <tr>
                    <td colSpan="5" className="text-center py-8 text-gray-500">No orders strictly match this server query.</td>
                  </tr>
                )}
              </tbody>
            </table>
          )}
        </div>
        
        {/* Backend Pagination */}
        <div className="px-6 py-4 border-t border-gray-100 flex flex-col sm:flex-row justify-between items-center text-sm text-gray-500 gap-4 bg-gray-50">
           <span>Total Mongoose Matches: <strong className="text-black">{totalRecords}</strong> db records</span>
           
           <div className="flex space-x-1 items-center">
             <button 
                onClick={() => setPage(p => Math.max(1, p - 1))}
                disabled={page === 1}
                className="px-3 py-1 border border-gray-300 bg-white hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-medium rounded-sm text-black"
             >
                Previous
             </button>
             
             <span className="px-3 py-1 font-medium text-black">
                Page {page} of {totalPages === 0 ? 1 : totalPages}
             </span>
             
             <button 
                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                disabled={page >= totalPages || totalPages === 0}
                className="px-3 py-1 border border-gray-300 bg-white hover:bg-gray-100 disabled:opacity-50 disabled:cursor-not-allowed transition-colors font-medium rounded-sm text-black"
             >
                Next
             </button>
           </div>
        </div>

      </div>

      {/* Order Detail Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm" onClick={closeModal}>
          <div className="bg-white rounded-lg shadow-xl w-full max-w-4xl max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center p-6 border-b border-gray-100 sticky top-0 bg-white z-10">
              <h2 className="text-2xl font-serif text-brand">Order #{selectedOrder?._id}</h2>
              <button onClick={closeModal} className="text-gray-500 hover:text-black">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
              </button>
            </div>
            
            <div className="p-6">
              {modalLoading || !selectedOrder ? (
                <div className="py-12"><Loader /></div>
              ) : (
                <div className="space-y-8">
                  {/* Timeline View */}
                  <div className="mb-8">
                    <h3 className="text-lg font-bold text-gray-800 mb-4">Order Timeline</h3>
                    <div className="flex flex-col md:flex-row justify-between items-center gap-4 relative">
                      <div className="absolute left-[50%] md:left-0 md:top-1/2 md:-translate-y-1/2 h-full md:h-1 w-1 md:w-full bg-gray-200 -z-10"></div>
                      
                      {['pending', 'processing', 'shipped', 'delivered'].map((step, idx) => {
                        const statusOrder = ['pending', 'processing', 'shipped', 'delivered'];
                        const currentStatusIdx = statusOrder.indexOf(selectedOrder.status);
                        const isCompleted = currentStatusIdx >= idx;
                        const isCancelled = selectedOrder.status === 'cancelled';
                        
                        let bgColor = isCompleted ? 'bg-brand' : 'bg-gray-200';
                        if (isCancelled && idx > 0) bgColor = 'bg-gray-200';
                        if (isCancelled && idx === 0) bgColor = 'bg-red-500';

                        return (
                          <div key={step} className="flex flex-col items-center bg-white px-2">
                            <div className={`w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-bold ${bgColor}`}>
                              {isCompleted && !isCancelled ? '✓' : (isCancelled && idx === 0 ? '✗' : idx + 1)}
                            </div>
                            <span className={`text-xs font-bold uppercase mt-2 ${isCompleted && !isCancelled ? 'text-brand' : (isCancelled && idx===0 ? 'text-red-500' : 'text-gray-400')}`}>
                              {isCancelled && idx === 0 ? 'Cancelled' : step}
                            </span>
                          </div>
                        )
                      })}
                    </div>
                  </div>

                  {/* Order Items & Info Summary */}
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <div className="bg-gray-50 p-4 rounded">
                      <h4 className="font-bold text-sm text-gray-700 uppercase mb-3">Customer & Shipping</h4>
                      <p className="text-sm"><strong>Name:</strong> {selectedOrder.user?.name || selectedOrder.shippingAddress?.fullName}</p>
                      <p className="text-sm"><strong>Email:</strong> {selectedOrder.user?.email}</p>
                      <p className="text-sm mt-2"><strong>Address:</strong><br/>
                        {selectedOrder.shippingAddress?.street}<br/>
                        {selectedOrder.shippingAddress?.city}, {selectedOrder.shippingAddress?.state} {selectedOrder.shippingAddress?.zipCode}<br/>
                        {selectedOrder.shippingAddress?.country}
                      </p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded">
                      <h4 className="font-bold text-sm text-gray-700 uppercase mb-3">Payment Info</h4>
                      <p className="text-sm flex items-center gap-2">
                        <strong>Status:</strong> 
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold tracking-wide uppercase ${selectedOrder.payment?.status === 'paid' ? 'bg-green-100 text-green-800' : 'bg-red-50 text-red-800'}`}>
                          {selectedOrder.payment?.status}
                        </span>
                      </p>
                      <p className="text-sm mt-2"><strong>Method:</strong> {selectedOrder.payment?.method?.toUpperCase()}</p>
                      <p className="text-sm mt-2"><strong>Total Amount:</strong> <span className="font-bold border-b border-gray-300 pb-0.5">${(selectedOrder.totalAmount || selectedOrder.total).toFixed(2)}</span></p>
                      {selectedOrder.trackingNumber && (
                        <p className="text-sm mt-2"><strong>Tracking:</strong> {selectedOrder.trackingNumber}</p>
                      )}
                    </div>
                  </div>

                  {/* Items List */}
                  <div>
                    <h4 className="font-bold text-sm text-gray-700 uppercase mb-3 border-b pb-2">Order Items</h4>
                    <div className="space-y-3">
                      {selectedOrder.items.map((item, idx) => (
                        <div key={idx} className="flex justify-between items-center text-sm border border-gray-100 p-3 rounded">
                          <div className="flex items-center gap-3">
                            {item.product?.images?.[0] && (
                              <img src={typeof item.product.images[0] === 'object' ? item.product.images[0].url : item.product.images[0]} alt={item.name} className="w-12 h-12 rounded object-cover" />
                            )}
                            <div>
                              <p className="font-bold text-brand">{item.name}</p>
                              <p className="text-xs text-gray-500">Qty: {item.quantity} | {item.color && `Color: ${item.color}`} {item.size && `Size: ${item.size}`}</p>
                            </div>
                          </div>
                          <p className="font-bold">${((item.price || item.product?.price) * item.quantity).toFixed(2)}</p>
                        </div>
                      ))}
                    </div>
                  </div>
                  
                  <div className="flex justify-end gap-3 pt-4 border-t border-gray-100">
                     <Link to={`/admin/orders/${selectedOrder._id}`} className="px-4 py-2 border border-gray-300 text-sm font-medium hover:bg-gray-50 rounded">Full Page View</Link>
                     <button onClick={() => window.open(`/admin/orders/${selectedOrder._id}?print=true`, '_blank')} className="px-4 py-2 bg-brand text-white text-sm font-medium hover:bg-gold rounded">Print Invoice</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      <ConfirmationModal 
        isOpen={confirmModal.isOpen}
        onClose={() => setConfirmModal({ ...confirmModal, isOpen: false })}
        onConfirm={confirmAction}
        title={confirmModal.title}
        message={confirmModal.message}
        type="warning"
        confirmText="Confirm"
      />
    </div>
  );
};

export default OrderList;

