  useEffect(() => {
    const fetchHomeData = async () => {
      try {
        setLoading(true);
        const data = await productService.getProducts({ limit: 4 });
        setFeaturedProducts(data.data || []);
      } catch (error) {
        console.error("Error fetching home products", error);
      } finally {
        setLoading(false);
      }
    };
    fetchHomeData();
  }, []);

  const [currentSlide, setCurrentSlide] = useState(0);
  const [current, setCurrent] = useState(0);
  const [visible, setVisible] = useState(true);

  const slides = [
    { lang: 'EN', dir: 'ltr', title: 'Where Every Stitch Tells a Story of Timeless Elegance', sub: 'Our handcrafted luxury bags are more than accessories — they are a statement of who you are.' },
    { lang: 'AR', dir: 'rtl', title: 'حيث تحكي كل غرزة قصة أناقة خالدة', sub: 'حقائبنا الفاخرة ليست مجرد إكسسوار — إنها تعبير عن شخصيتك الفريدة.' },
    { lang: 'TR', dir: 'ltr', title: 'Her Dikiş Zamansız Bir Zarafet Hikayesi Anlatır', sub: 'El yapımı lüks çantalarımız sadece aksesuar değil — kim olduğunuzun ifadesidir.' }
