            </div>
          </div>
        </div>
        
        {/* RIGHT: Image Slideshow */}
        <div className="flex-1 relative min-h-[50vh] md:min-h-screen mt-10 md:mt-0 animate-fade-in overflow-hidden">
          <div className="absolute inset-0 bg-brand/5 z-10 pointer-events-none"></div>
          
